this:AddTalk("<p><n color=\"255,255,0,0\">抽奖达1000次奖励绝世坐骑！</n></p>")
this:AddTaskCmdItem("[一连抽]金子抽奖：100锭金子/次(0)", "v610001", 1000, 2)
this:AddCloseItem("------------------------------(0)")
this:AddTaskCmdItem("[十连抽]金子抽奖：1000锭金子/次(0)", "v610001", 1000, 12)
this:AddDialogItem("离开","TaskDialog")
end

